            <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl p-8 shadow-xl">
                 <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-6">Get in Touch</h3>
